func TestEnumNetworkACLRuleScopeEnum(t *testing.T) {
	t.Run("NewFromString_management", func(t *testing.T) {
		t.Parallel()
		val, err := NewNetworkACLRuleScopeEnumFromString("management")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, NetworkACLRuleScopeEnum("management"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_authentication", func(t *testing.T) {
		t.Parallel()
		val, err := NewNetworkACLRuleScopeEnumFromString("authentication")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, NetworkACLRuleScopeEnum("authentication"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_tenant", func(t *testing.T) {
		t.Parallel()
		val, err := NewNetworkACLRuleScopeEnumFromString("tenant")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, NetworkACLRuleScopeEnum("tenant"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_dynamic_client_registration", func(t *testing.T) {
		t.Parallel()
		val, err := NewNetworkACLRuleScopeEnumFromString("dynamic_client_registration")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, NetworkACLRuleScopeEnum("dynamic_client_registration"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewNetworkACLRuleScopeEnumFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewNetworkACLRuleScopeEnumFromString("management")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesGetNetworkACLsResponseContent(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &GetNetworkACLsResponseContent{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *GetNetworkACLsResponseContent
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

